algorithms_recursion_c.content:
#include "recursion.h"
#include <stdbool.h>

static void foo_rec(bool *bits, int n, int i, FooStats *stats) {
    stats->calls++;

    if (i == n) {
        stats->leaves++;
        return;
    }

    bits[i] = true;
    foo_rec(bits, n, i + 1, stats);

    bits[i] = false;
    foo_rec(bits, n, i + 1, stats);
}

FooStats foo(int n) {
    FooStats stats = {0, 0};
    bool bits[n > 0 ? n : 1];
    foo_rec(bits, n, 0, &stats);
    return stats;
}

